// S7: Context Card — สรุปข้อมูลสินค้า
const input = $input.first().json;

const ctx = {
  product: input.product || input.product_name || 'สินค้าไทย',
  category: input.category || 'ทั่วไป',
  price: input.price ? `฿${input.price}` : 'N/A',
  platform: input.platform || 'TikTok',
  style: input.style || 'sales',
  lang: input.lang || 'ภาษาไทย',
  audience: input.audience || 'ทั่วไป',
  usp: input.usp || ''
};

const styleDesc = {
  sales: 'ขายตรง โน้มน้าวให้ซื้อ ใช้ urgency',
  educational: 'ให้ความรู้ อธิบายข้อมูล น่าเชื่อถือ',
  entertainment: 'สนุก ฮา ติดเทรนด์ ดึงดูดคนดู'
};

const prompt = `คุณคือ AI ผู้เชี่ยวชาญด้านคอนเทนต์ TikTok สำหรับตลาดไทย

สร้างคอนเทนต์ ${ctx.platform} สำหรับสินค้า "${ctx.product}" (หมวด: ${ctx.category}) ราคา ${ctx.price}
สไตล์: ${styleDesc[ctx.style] || ctx.style}
ภาษา: ${ctx.lang}
${ctx.usp ? 'จุดเด่น: ' + ctx.usp : ''}

ตอบเป็น JSON เท่านั้น ไม่มีข้อความอื่น:
{
  "hook": "ประโยคเปิดดึงดูด 1-2 ประโยค",
  "script": ["ขั้นที่ 1", "ขั้นที่ 2", "ขั้นที่ 3", "ขั้นที่ 4", "CTA"],
  "caption": "แคปชั่นพร้อมโพสต์ พร้อม emoji",
  "hashtags": ["#แฮชแท็ก1", "#แฮชแท็ก2", "#แฮชแท็ก3", "#แฮชแท็ก4", "#แฮชแท็ก5"],
  "criticScore": "คะแนน 0-10 ทศนิยม 1 ตำแหน่ง",
  "criticFeedback": "คำแนะนำปรับปรุง 1 ประโยค"
}`;

return [{ json: { ctx, prompt } }];

// Parse Gemini response + add metadata
const raw = $input.first().json;
let result;

try {
  const text = raw.candidates?.[0]?.content?.parts?.[0]?.text || '{}';
  result = JSON.parse(text);
} catch (e) {
  // Fallback mock
  const ctx = $('S7 Context Card').first().json.ctx;
  result = {
    hook: `${ctx.product} ดีจริงหรือ? เฉลยตอนท้าย!`,
    script: [
      `เปิดด้วยคำถาม: "${ctx.product} คืออะไร?"",
      'อธิบายที่มาและความพิเศษ',
      'แสดง 3 ข้อดีหลัก',
      'Social proof จากลูกค้าจริง',
      'CTA: กดลิงก์ด้านล่าง ส่งฟรีทั่วไทย!'
    ],
    caption: `✨ ${ctx.product} — คุณภาพพรีเมียม\n💰 ราคาพิเศษ ${ctx.price}\n🚚 ส่งฟรีทั่วไทย\n📩 DM หรือกดลิงก์ใน Bio`,
    hashtags: [`#${ctx.product.replace(/\s/g,'')}`, '#สินค้าไทย', '#OTOP', '#TikTokShop', '#Openthai.ai'],
    criticScore: (7 + Math.random() * 2.5).toFixed(1),
    criticFeedback: 'เพิ่ม Social Proof และ Urgency จะช่วยเพิ่ม Conversion'
  };
}

result.source = raw.candidates ? 'gemini' : 'mock';
result.model = 'gemini-1.5-flash';
result.timestamp = new Date().toISOString();

return [{ json: result }];
